INSERT INTO `products` (`id`, `category_id`, `name`, `slug`, `description`, `price`, `stock`, `image`, `brand`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 1, 'Pioneer DDJ-FLX6', 'pioneer-ddj-flx6', 'Четириканален DJ контролер, съвместим с rekordbox и Serato DJ Pro. Идеален за клубна употреба.', 459.99, 3, 'pioneer-ddj-flx6-1775084747.webp', 'Pioneer DJ', 1, '2026-03-12 16:48:40', '2026-04-04 18:40:46'),
(2, 1, 'Denon Prime Go', 'denon-dj-sc6000m', 'Denon PRIME GO е ултракомпактен, напълно самостоятелен 2‑деков DJ контролер, създаден за мобилни DJ-и, корпоративни събития, сватби, барове и ситуации, в които мобилността и надеждността са ключови. Благодарение на вградената литиево-йонна батерия с до 4 часа автономна работа, PRIME GO позволява да свириш навсякъде – без лаптоп, без външно захранване и без компромис в качеството.\r\n\r\nКонтролерът работи с мощната платформа Engine DJ OS, която предлага стрийминг услуги, интелигентно управление на плейлисти, бърза навигация и стабилност при дълги сетове. Големият 7-инчов мултитъч дисплей осигурява лесен контрол върху библиотеката, ефектите и вълновите форми.\r\n\r\nPRIME GO разполага с професионални XLR изходи, два микрофонни входа, чувствителни джог колела и 8 перформанс пада на дек. Компактният размер и здравата конструкция го правят идеален за DJ-и, които искат максимална свобода и надеждност в движение.\r\n\r\nТехнически характеристики (описани текстово)\r\n\r\nDenon PRIME GO е самостоятелен 2‑деков DJ контролер с 7-инчов мултитъч дисплей и вградена батерия с до 4 часа работа. Разполага с два микрофонни входа, XLR master изходи, USB и SD слотове за медия, Wi‑Fi за стрийминг услуги и 8 перформанс пада на дек. Джог колелата са чувствителни и компактни, а устройството е леко и лесно за пренасяне.\r\n\r\nПредимства\r\n\r\nНапълно самостоятелен контролер – работи без лаптоп\r\nВградена батерия за до 4 часа автономност\r\n7” мултитъч дисплей за бърза и интуитивна работа\r\nПрофесионални XLR изходи и два микрофонни входа\r\nСтрийминг услуги и Wi‑Fi свързаност\r\nИзключително компактен и подходящ за мобилни DJ-и', 1299.99, 1, 'denon-prime-go-1775224252.png', 'Denon', 1, '2026-03-12 16:48:40', '2026-04-03 15:07:34'),
(3, 2, 'Allen & Heath Xone:43', 'allen-heath-xone43', 'Аналогов 4-канален DJ микшер с вградени филтри. Легендарен звук.', 389.00, 4, NULL, 'Allen & Heath', 0, '2026-03-12 16:48:40', '2026-04-05 16:15:55'),
(4, 2, 'Pioneer DJM-900NXS2', 'pioneer-djm-900nxs2', 'Флагманският клубен стандарт — 4-канален цифров микшер.', 979.00, 1, NULL, 'Pioneer DJ', 0, '2026-03-12 16:48:40', '2026-04-05 12:53:29'),
(5, 3, 'Sennheiser HD 25', 'sennheiser-hd-25', 'Леки и издръжливи DJ слушалки с отлична изолация. Индустриален стандарт.', 97.99, 4, NULL, 'Sennheiser', 0, '2026-03-12 16:48:40', '2026-04-05 16:15:59'),
(6, 3, 'Audio-Technica ATH-M50x', 'audio-technica-ath-m50x', 'Студийни слушалки с изключително детайлен звук. Сгъваема конструкция.', 79.99, 6, NULL, 'Audio-Technica', 0, '2026-03-12 16:48:40', '2026-04-05 16:16:04'),
(7, 4, 'QSC K12.2', 'qsc-k122', 'Активен говорител 2000W с DSP обработка. Подходящ за клубове и събития.', 599.00, 3, NULL, 'QSC', 0, '2026-03-12 16:48:40', '2026-04-05 12:52:07'),
(8, 5, 'Pioneer CDJ-3000', 'pioneer-cdj-3000', 'Флагманският медиен плейър с 9-инчов сензорен дисплей и цифров I/O.', 1129.00, 2, NULL, 'Pioneer DJ', 0, '2026-03-12 16:48:40', '2026-04-05 16:16:13'),
(9, 2, 'Rane Seventy-Two MKII', 'rane-seventy-two-mkii', 'Професионален 2-канален DJ микшер', 810.00, 4, '0', 'Rane DJ', 0, '2026-03-19 12:30:49', '2026-04-05 16:16:22'),
(10, 1, 'Pioneer DJ DDJ-FLX10', 'pioneer-dj-ddj-flx10', 'DDJ-FLX10 е 4-канален DJ контролер за Rekordbox и Serato DJ Pro. Той включва множество чисто нови функции, включително технологията Track Separation, която дава възможност за нови творчески възможности, като например лесно изпълнение на mash-ups в движение, без да е необходимо да се подготвят предварително парчета.\r\n\r\nЗареждайте обичайните песни от музикалната си библиотека и създавайте ремикси и машъпи в движение, като независимо манипулирате 3-те основни части на музиката: вокали, барабани и инструменти (други инструменти, включително бас и синтезатори). Има специални цветни бутони за управление на всяка част, така че винаги ще имате ясна визуална представа за това какво се възпроизвежда.\r\n\r\nАКТИВНА ЧАСТ И ЧАСТ ISO\r\nРегулирайте индивидуално силата на звука на вокалите, барабаните или инструментите или ги изключете напълно.\r\n\r\nFX PART SELECT\r\nИзберете към кои части на песента искате да приложите ефекти.\r\n\r\nМОМЕНТАЛНО УДВОЯВАНЕ НА ЧАСТ\r\nИзолирайте конкретна част от музиката\r\n\r\nЗареждайте обичайните песни от музикалната си библиотека и създавайте ремикси и машъпи в движение, като независимо манипулирате 3-те основни части на музиката: вокали, барабани и инстументи (други инструменти, включително бас и синтезатори). Има специални цветни бутони за управление на всяка част, така че винаги ще имате ясна визуална представа за това какво се възпроизвежда. Регулирайте индивидуално силата на звука на вокалите, барабаните или инструментите или ги изключете напълно.\r\n\r\nРазширен на Jog дисплей\r\n\r\nПерсонализирайте информацията, която виждате на джогинга, за да не се налага да откъсвате поглед от конзолата. Изберете един от 4 режима, някои от които показват 3-лентови форми на вълната (само за rekordbox), и следете информацията за Mix Point Link и за анализ на позицията на вокала в rekordbox, както и състоянието на Performance Pad.\r\n\r\nРЕЖИМ DECK INFO\r\nПоказва информация за дека, включително общата форма на вълната. (Когато използвате Serato DJ Pro, този режим показва виртуалния дек на Serato DJ Pro.)\r\n\r\nWAVEFORM MODE\r\nПоказва увеличените звукови вълни за 2 дека.\r\n\r\nПОКАЗВАНЕ НА ARTWORK\r\nПоказва обложката на песента, която се възпроизвежда.\r\n\r\nПОКАЗВАНЕ НА ЛОГОТО НА ДИДЖЕЯ\r\nПоказва вашето собствено лого или любимо изображение на всеки дек, след използване на инструмента за прехвърляне на изображения за PC/Mac\r\n\r\nНов Mix Point Link за смесване за безпроблемни преходи\r\n\r\nВъзползвайте се от напълно нова концепция за възпроизвеждане в Rekordbox, която ви позволява да създавате гладки музикални прогресии в сетовете си чрез свързване на микс точките в песните, така че следващата песен да започне в идеалния момент. Можете да зададете следващата песен да започне от началото на мелодията си, когато вокалът на текущата песен свърши, като по този начин осигурите плавен преход без звуков сблъсък. Не е необходимо да отброявате или да натискате ръчно бутона за възпроизвеждане, което също така оставя ръцете ви свободни за създаване на машъпи или добавяне на ефекти.\r\n\r\nDMX изход за функцията за осветление на Rekordbox\r\n\r\nОживете изпълненията си със светлинни ефекти, които съответстват на настроението на възпроизвежданите песни. Това е лесно с функцията Rekordbox Lighting и благодарение на DMX изхода на DDJ-FLX10 не се нуждаете от друго оборудване, като например външен DMX интерфейс. Просто свържете DMX-съвместимо осветително оборудване към контролера и използвайте Rekordbox, за да създадете персонализирани светлинни ефекти, или настройте софтуера автоматично да адаптира цвета и движението на светлините в съответствие с музиката.\r\n\r\nРазработена 4-сензорна система MAGVEL FADER\r\n\r\nУсъвършенстванa от 2-сензорната система на DDJ-1000, MAGVEL FADER на DDJ-FLX10 използва 4-сензорна система. Това ви позволява да правите и най-малките корекции на силата на звука, без значение колко малко е движението на кросфедера, което дава възможност за по-музикални изпълнения.\r\n\r\nСъвместимост с Rekordbox и Serato DJ Pro\r\n\r\nDDJ-FLX10 предлага безплатна plug-and-play съвместимост с rekordbox и Serato DJ Pro, което ви дава възможност да контролирате любимото си софтуерно приложение. Поддръжката на DVS е налична за rekordbox чрез избрани абонаментни планове, а за Serato - чрез платен лиценз/абонамент за Serato DJ Expansions или Serato DJ Suite', 1799.99, 5, 'pioneer-dj-ddj-flx10-1775085412.png', 'Pioneer DJ', 1, '2026-04-01 17:19:31', '2026-04-03 15:06:59'),
(12, 1, 'Pioneer DJ DDJ-FLX4', 'pioneer-ddj-flx4', 'Pioneer DJ DDJ-FLX4 е 2-канален контролер с улеснен и удобен за потребителя дизайн и професионално усещане, съвместим с rekordbox DJ и Serato DJ Lite.\r\n\r\nСъвместимост с rekordbox и Serato\r\nМожете да използвате DJ софтуер rekordbox или Serato DJ Lite безплатно, като свържете вашия PC/Mac към DDJ-FLX4. А ако искате да надстроите до Serato DJ Pro, може да закупите лиценз или абонамент за първокласната версия на софтуера.\r\n\r\nПоддръжка на няколко устройства\r\nНезависимо дали искате да се свържете с PC, Mac, iPhone, iPad или телефон или таблет с Android, DDJ-FLX4 е с универсален дизайн. Още по-добре, ако използвате контролера с rekordbox за iOS/Android, когато актуализацията стане достъпна в началото на 2023 г., ще можете да се свържете с устройството си чрез Bluetooth® или USB кабел. \r\n\r\nУдобен за потребителя преносим дизайн и професионално оформление\r\nРазположението на бутоните за управление на DDJ-FLX4 улеснява обучението за диджей и е наследено от професионалните диджейски продукти на Pioneer. Всичко е лесно за използване и подредено, което също така прави контролера достатъчно компактен, за да го вземете навсякъде, където искате да тренирате или да свирите.\r\n\r\nЧисто нови функции за интелигентно смесване\r\nНе знаете как да смесвате? Не се притеснявайте, можете да започнете веднага с функцията Smart Fader, която автоматично регулира силата на звука, силата на баса и BPM на музиката, така че да можете плавно да преминавате от една песен към друга, като просто преместите фейдърите на канала или кросфейдъра . Плюс това, със Smart CFX можете просто да завъртите копче, за да приложите комбинация от ефекти.\r\n\r\nБезпроблемна интеграция с избрани услуги за стрийминг\r\nRekordbox е съвместим с множество услуги за стрийминг. Така че можете да избирате от милионите песни, налични в платформите TIDAL, Beatport Streaming, Beatsource Streaming и SoundCloud Go+ (изискват се абонаменти), и да ги смесвате заедно на DDJ-FLX4. Можете също така да използвате всички ефекти и функции за изпълнение, за да подправите любимите си песни и да създадете свой собствен звук.\r\n\r\nUSB аудио изход за звук от микрофон\r\nDDJ-FLX4 улеснява работата ви, ако искате да бъдете водещ или да пеете по време на сета си, тъй като смесва звука вместо вас. Така че можете да свържете контролера към едно устройство и да чуете звука на вашия микс заедно със звука от микрофона, стига да нямате свързано Bluetooth® устройство. Това също така прави DDJ-FLX4 идеален избор, ако искате да излъчвате сетовете си на живо, защото можете да правите всичко това от едно устройство.\r\n\r\nСъвместим DJ софтуер\r\nrekordbox за Mac/Windows\r\nrekordbox за iOS/Android (предстои в началото на следващата година)\r\nSerato DJ Lite\r\nSerato DJ Pro (лицензът/абонаментът не е включен)\r\n\r\nСпецификации:\r\nЧестотен диапазон: 20 - 20000 Hz\r\nширина: 18,98 инча\r\nВисочина: 2,33 инча\r\nДълбочина: 10,74 инча\r\nТегло: 4,63 фунта\r\nЗвукова карта: 16 бита/24 бита, 44,1 kHz/48 kHz\r\nСъотношение сигнал/шум: 103 dB\r\nИзкривяване: < 0,005 % (USB)\r\nКанали: 2\r\nДжог: 111,6 мм\r\nBeat FX: да\r\nColor FX: да\r\nSampler: rekordbox 16 слот / Serato DJ Lite 4 слот\r\nHot Cue: rekordbox 8 / Serato DJ Lite 4\r\nPad Modes rekordbox: Hot Cue / Pad FX 1 / Pad FX 2 / Beat Jump\r\nAuto Beat Loop: да\r\n\r\nВходове: \r\n1 микрофон (1/4 инча TS жак)\r\nИзходи:\r\n1 МАСТЕР (RCA)\r\n1 ТЕЛЕФОН (3,5 мм стерео мини жак)\r\nUSB: 2 комплекта USB Type-C порт (PC/Mac връзка и захранване ×1, само захранване ×1)\r\n\r\nГаранция: 36 месеца', 349.99, 10, 'pioneer-dj-ddj-flx4-1775405873.png', 'Pioneer DJ', 1, '2026-04-01 22:45:11', '2026-04-05 16:17:53'),
